  const APInt *C1, *M;
  Value *X;
  if (match(Op1, m_And(m_OneUse(m_Sub(m_APInt(C1), m_Value(X))), m_APInt(M)))) {
    // M should be -N where N is a power of 2 (i.e., M clears low bits)
    APInt N = -*M;
